/**
 * Workspace Page
 * Main workspace with chat, engagement pipeline, and outputs
 */

import React, { useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { useSession, useChat, useWorkspace, useEngagement, useAuth } from '../hooks';
import { SessionSidebar } from '../components/sessions';
import { ChatPanel } from '../components/chat';
import { WorkspacePanel } from '../components/workspace';
import { ThreePanelLayout } from '../components/layouts';
import { sessionService } from '../services';

export const WorkspacePage: React.FC = () => {
  const { sessionId } = useParams<{ sessionId?: string }>();
  const { identity } = useAuth();
  const {
    sessions,
    activeSessionId,
    isLoading,
    error,
  } = useSession();
  const { engagement } = useEngagement();

  // Load sessions on mount
  useEffect(() => {
    const loadSessions = async () => {
      try {
        await sessionService.listSessions();
      } catch (err) {
        console.error('Failed to load sessions:', err);
      }
    };

    loadSessions();
  }, []);

  const handleSessionSelect = async (id: string) => {
    try {
      const session = await sessionService.getSession(id);
      if (session) {
        // Load engagement for this session
        // This will be handled by the store and services
      }
    } catch (err) {
      console.error('Failed to select session:', err);
    }
  };

  const handleSessionCreate = async () => {
    try {
      const request = {
        user_id: identity?.id || 'unknown',
        name: `Session ${new Date().toLocaleString()}`,
      };
      await sessionService.createSession(request);
    } catch (err) {
      console.error('Failed to create session:', err);
    }
  };

  const handleSessionRename = async (id: string) => {
    const newName = prompt('New session name:');
    if (newName) {
      try {
        await sessionService.updateSession(id, { name: newName });
      } catch (err) {
        console.error('Failed to rename session:', err);
      }
    }
  };

  const handleSessionDelete = async (id: string) => {
    if (
      confirm(
        'Are you sure you want to delete this session?'
      )
    ) {
      try {
        await sessionService.deleteSession(id);
      } catch (err) {
        console.error('Failed to delete session:', err);
      }
    }
  };

  const handleSearch = (query: string) => {
    // Filter sessions based on search query
    // This will be handled by the store
  };

  const currentSessionId = sessionId || activeSessionId || undefined;

  return (
    <ThreePanelLayout
      leftPanel={
        <SessionSidebar
          sessions={sessions}
          activeSessionId={currentSessionId}
          onSessionSelect={handleSessionSelect}
          onSessionCreate={handleSessionCreate}
          onSessionRename={handleSessionRename}
          onSessionDelete={handleSessionDelete}
          onSearch={handleSearch}
          isLoading={isLoading}
        />
      }
      centerPanel={
        <ChatPanel sessionId={currentSessionId} />
      }
      rightPanel={
        <WorkspacePanel />
      }
      leftWidth={20}
      rightWidth={30}
    />
  );
};

